final:
module RefModule(
   input                clk,
   input                rst_n,

   output reg [11:0]    Q  
);
    reg [11:0] binary_counter;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (!rst_n) binary_counter <= 12'b0;
        else binary_counter <= binary_counter + 1;
    end

    always @(*) begin
        Q = binary_counter ^ (binary_counter >> 1);
    end
endmodule
